1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteStep = {
9	  op: "quote";
10	  items: Item[];
11	};
12	
13	export type Damage = { itemType: string; amount: number };
14	
15	export type ClaimStep = {
16	  op: "claim";
17	  policy: number;
18	  incident: { cause: string; damages: Damage[] };
19	};
20	
21	export type Step = QuoteStep | ClaimStep;
22	
23	export type Scenario = {
24	  customer: { yearsWithMHPCO: number };
25	  steps: Step[];
26	};
27	
28	export type QuoteResult = { premium: number };
29	export type ClaimResult = { payout: number; remainingCap: number };
30	export type StepResult = QuoteResult | ClaimResult;
31	
32	export type ScenarioResult = {
33	  results: StepResult[];
34	};
35	
36	const PROCESSING_FEE = 5;
37	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
38	const FOLLOW_UP_CONTRACT_DISCOUNT_RATE = 0.15;
39	const BLOCK_OF_THREE_DISCOUNT = 15;
40	const CURSE_SURCHARGE_RATE = 0.5;
41	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
42	const HIGH_ENCHANTMENT_THRESHOLD = 5;
43	const LOYALTY_DISCOUNT_RATE = 0.2;
44	const LOYALTY_YEARS_THRESHOLD = 2;
45	
46	type CatalogEntry = { basePremium: number; insuranceValue: number };
47	
48	const ITEM_CATALOG: Record<string, CatalogEntry> = {
49	  sword: { basePremium: 100, insuranceValue: 1000 },
50	  amulet: { basePremium: 60, insuranceValue: 600 },
51	  staff: { basePremium: 80, insuranceValue: 800 },
52	  potion: { basePremium: 40, insuranceValue: 400 },
53	  rune: { basePremium: 25, insuranceValue: 250 },
54	  moonstone: { basePremium: 25, insuranceValue: 250 },
55	};
56	
57	const catalogEntryFor = (type: string): CatalogEntry => {
58	  const entry = ITEM_CATALOG[type];
59	  if (!entry) {
60	    throw new Error(`Unknown item type: ${type}`);
61	  }
62	  return entry;
63	};
64	
65	const DEDUCTIBLE = 100;
66	const CAP_MULTIPLIER = 2;
67	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
68	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
69	
70	const BLOCK_OF_THREE_ELIGIBLE_TYPES = ["rune", "moonstone"];
71	
72	const blockOfThreeDiscount = (alikeComponentCount: number): number =>
73	  alikeComponentCount === 3 ? BLOCK_OF_THREE_DISCOUNT : 0;
74	
75	const countItemsOfType = (items: Item[], type: string): number =>
76	  items.filter((item) => item.type === type).length;
77	
78	const isCursed = (item: Item): boolean => item.cursed === true;
79	const isHighlyEnchanted = (item: Item): boolean =>
80	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
81	
82	const ITEM_SURCHARGE_RATES: ReadonlyArray<{
83	  applies: (item: Item) => boolean;
84	  rate: number;
85	}> = [
86	  { applies: isCursed, rate: CURSE_SURCHARGE_RATE },
87	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_SURCHARGE_RATE },
88	];
89	
90	const basePremiumFor = (item: Item): number => catalogEntryFor(item.type).basePremium;
91	
92	const surchargesForItem = (item: Item): number => {
93	  const base = basePremiumFor(item);
94	  return ITEM_SURCHARGE_RATES.reduce(
95	    (sum, { applies, rate }) => sum + (applies(item) ? base * rate : 0),
96	    0,
97	  );
98	};
99	
100	const sumItemSpecificSurcharges = (items: Item[]): number =>
101	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
102	
103	const calculateBasePremium = (items: Item[]): number => {
104	  const subtotal = items.reduce((sum, item) => sum + basePremiumFor(item), 0);
105	  const totalDiscount = BLOCK_OF_THREE_ELIGIBLE_TYPES.reduce(
106	    (sum, type) => sum + blockOfThreeDiscount(countItemsOfType(items, type)),
107	    0,
108	  );
109	  return subtotal - totalDiscount;
110	};
111	
112	const firstContractSurcharge = (basePremium: number): number =>
113	  basePremium * FIRST_CONTRACT_SURCHARGE_RATE;
114	
115	const qualifiesForLoyaltyDiscount = (yearsWithMHPCO: number): boolean =>
116	  yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
117	
118	const loyaltyDiscount = (basePremium: number, yearsWithMHPCO: number): number =>
119	  qualifiesForLoyaltyDiscount(yearsWithMHPCO) ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
120	
121	const followUpContractDiscount = (basePremium: number, isFollowUp: boolean): number =>
122	  isFollowUp ? basePremium * FOLLOW_UP_CONTRACT_DISCOUNT_RATE : 0;
123	
124	const quote = (
125	  step: QuoteStep,
126	  customer: Scenario["customer"],
127	  isFollowUp: boolean,
128	): QuoteResult => {
129	  const basePremium = calculateBasePremium(step.items);
130	  const itemSurcharges = sumItemSpecificSurcharges(step.items);
131	  const premium = Math.ceil(
132	    basePremium +
133	      itemSurcharges +
134	      firstContractSurcharge(basePremium) -
135	      loyaltyDiscount(basePremium, customer.yearsWithMHPCO) -
136	      followUpContractDiscount(basePremium, isFollowUp) +
137	      PROCESSING_FEE,
138	  );
139	  return { premium };
140	};
141	
142	type Policy = { items: Item[]; cap: number };
143	
144	const insuranceSumOf = (items: Item[]): number =>
145	  items.reduce((sum, item) => sum + catalogEntryFor(item.type).insuranceValue, 0);
146	
147	const initialCapFor = (items: Item[]): number => insuranceSumOf(items) * CAP_MULTIPLIER;
148	
149	const findInsuredItem = (policy: Policy, itemType: string): Item | undefined =>
150	  policy.items.find((item) => item.type === itemType);
151	
152	const payoutForDamage = (damage: Damage, insuredItem: Item | undefined): number => {
153	  const reimbursable =
154	    insuredItem && (insuredItem.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
155	      ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
156	      : damage.amount;
157	  return Math.max(0, reimbursable - DEDUCTIBLE);
158	};
159	
160	const claim = (step: ClaimStep, policy: Policy): ClaimResult => {
161	  const grossPayout = step.incident.damages.reduce(
162	    (sum, dmg) => sum + payoutForDamage(dmg, findInsuredItem(policy, dmg.itemType)),
163	    0,
164	  );
165	  const cappedPayout = Math.min(grossPayout, policy.cap);
166	  return { payout: Math.floor(cappedPayout), remainingCap: policy.cap - cappedPayout };
167	};
168	
169	export const runScenario = (scenario: Scenario): ScenarioResult => {
170	  const policies: Policy[] = [];
171	  let priorQuoteCount = 0;
172	  const results: StepResult[] = scenario.steps.map((step) => {
173	    if (step.op === "quote") {
174	      const isFollowUp = priorQuoteCount > 0;
175	      priorQuoteCount += 1;
176	      const result = quote(step, scenario.customer, isFollowUp);
177	      policies.push({ items: step.items, cap: initialCapFor(step.items) });
178	      return result;
179	    }
180	    const policy = policies[step.policy];
181	    const result = claim(step, policy);
182	    policy.cap = result.remainingCap;
183	    return result;
184	  });
185	  return { results };
186	};
